import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://www.prisma.io/docs/postgres/introduction/management-api";
const PLACEHOLDER_VALUE =
  "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSa";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Prisma Postgres API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:prisma-postgres",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const prismaPostgresFirewall = {",
    '  name: "prisma-postgres",',
    '  description: "Prisma Postgres Management API",',
    "  placeholders: {",
    `    PRISMA_POSTGRES_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.prisma.io",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.PRISMA_POSTGRES_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Prisma Postgres firewall config...");
  const ts = generateTypeScript();
  writeOutput("prisma-postgres", ts, import.meta.dirname);
}
